parameters.jsCode:
// Expand persisted alerts for per-item Discord dispatch.
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];
return items
  .filter(i => (i.channels || []).includes('discord'))
  .map(item => ({ json: item }));

// Format the alert as a Discord embed payload.
// Discord embeds support color coding, fields, and footer.
const item = $input.item.json;

// Map topic to a Discord embed sidebar color (decimal)
const topicColor = {
  crypto:     0xF7931A, // Bitcoin orange
  finance:    0x2ECC71, // green
  economy:    0x3498DB, // blue
  health:     0xE74C3C, // red
  ai:         0x9B59B6, // purple
  energy:     0xF1C40F, // yellow
  technology: 0x1ABC9C  // teal
};
const color = topicColor[item.topic_slug] || 0x95A5A6;

const topicEmoji = {
  crypto: '🪙', finance: '📈', economy: '🏦',
  health: '🏥', ai: '🤖', energy: '⚡', technology: '💻'
};
const emoji = topicEmoji[item.topic_slug] || '📰';

const embed = {
  title:       `${emoji} ${item.headline}`,
  description: item.summary_text,
  color,
  fields: [
    { name: 'Topic',       value: item.topic_slug.charAt(0).toUpperCase() + item.topic_slug.slice(1), inline: true },
    { name: 'Importance',  value: `${item.importance_score}/100`, inline: true },
    { name: 'Severity',    value: `${item.severity_score}/100`,   inline: true }
  ],
  footer: { text: item.source_name },
  timestamp: item.event_at
};

if (item.source_url) {
  embed.url = item.source_url;
}

return [{ json: { ...item, discord_payload: { embeds: [embed] } } }];

